class ProductionVerboseTree(
    private val tagPrefix: String,
    private val minPriority: Int
) : Timber.Tree() {

    override fun isLoggable(tag: String?, priority: Int): Boolean = priority >= minPriority

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val finalTag = buildTag(tag)
        if (message.length < 3900) {
            Log.println(priority, finalTag, message)
        } else {
            var i = 0
            val len = message.length
            while (i < len) {
                val end = (i + 3900).coerceAtMost(len)
                Log.println(priority, finalTag, message.substring(i, end))
                i = end
            }
        }
        if (t != null) {
            val st = Log.getStackTraceString(t)
            if (st.isNotBlank()) Log.println(priority, finalTag, st)
        }
    }

    private fun buildTag(tag: String?): String {
        val base = tag?.takeIf { it.isNotBlank() } ?: "Log"
        return "$tagPrefix-$base"
    }
}

class HttpLoggingInterceptor(
    private val label: String? = "OkHttp",
    private val logRequestBody: Boolean = true,
    private val logResponseBody: Boolean = true
) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val startNs = System.nanoTime()

        val reqHeaders = request.headers.toMap()
        val reqBodyStr = if (logRequestBody) requestBodyToString(request) else null

        AppLogger.apiRequest(
            label = label,
            method = request.method,
            url = request.url.toString(),
            headers = reqHeaders,
            requestBody = reqBodyStr
        )

        val response: Response = try {
            chain.proceed(request)
        } catch (t: Throwable) {
            AppLogger.exception(t, "API call failed: ${request.method} ${request.url}")
            throw t
        }

        val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)

        val respHeaders = response.headers.toMap()
        val respBodyStr = if (logResponseBody) peekResponseBody(response) else null

        AppLogger.apiResponse(
            label = label,
            url = response.request.url.toString(),
            code = response.code,
            headers = respHeaders,
            responseBody = respBodyStr,
            durationMs = tookMs
        )

        return response
    }

    private fun requestBodyToString(request: Request): String? {
        val body = request.body ?: return null
        return try {
            val buffer = Buffer()
            body.writeTo(buffer)
            val charset = body.contentType()?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
            if (isPlaintext(buffer)) buffer.readString(charset) else "<binary ${body.contentType() ?: "unknown"} (${buffer.size} bytes)>"
        } catch (t: Throwable) {
            "<unable to read request body: ${t.javaClass.simpleName}: ${t.message}>"
        }
    }

    private fun peekResponseBody(response: Response): String? {
        val body = response.body ?: return null
        return try {
            val peeked = response.peekBody(AppLogger.maxBodyChars.toLong().coerceAtLeast(1024L))
            val charset = peeked.contentType()?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
            val source = peeked.source()
            source.request(Long.MAX_VALUE)
            val buffer = source.buffer
            if (isPlaintext(buffer)) buffer.clone().readString(charset) else "<binary ${peeked.contentType() ?: "unknown"} (${peeked.contentLength()} bytes)>"
        } catch (t: Throwable) {
            "<unable to read response body: ${t.javaClass.simpleName}: ${t.message}>"
        }
    }

    private fun isPlaintext(buffer: Buffer): Boolean {
        return try {
            val prefix = Buffer()
            val byteCount = buffer.size.coerceAtMost(64)
            buffer.copyTo(prefix, 0, byteCount)
            for (i in 0 until 16) {
                if (prefix.exhausted()) break
                val codePoint = prefix.readUtf8CodePoint()
                if (Character.isISOControl(codePoint) && !Character.isWhitespace(codePoint)) return false
            }
            true
        } catch (_: EOFException) {
            false
        } catch (_: Throwable) {
            false
        }
    }
}

object DbLog {
    fun logQuery(
        dbName: String? = null,
        sql: String,
        args: Array<Any?>? = null,
        rows: Int? = null,
        durationMs: Long? = null
    ) {
        AppLogger.dbQuery(
            dbName = dbName,
            sql = sql,
            args = args?.toList(),
            rows = rows,
            durationMs = durationMs,
            success = true
        )
    }

    fun logQueryError(
        dbName: String? = null,
        sql: String,
        args: Array<Any?>? = null,
        durationMs: Long? = null,
        tr: Throwable
    ) {
        AppLogger.dbQuery(
            dbName = dbName,
            sql = sql,
            args = args?.toList(),
            rows = null,
            durationMs = durationMs,
            success = false,
            tr = tr
        )
    }
}

object AuthLog {
    fun success(method: String, identifier: String?, metadata: Map<String, Any?>? = null) {
        AppLogger.authAttempt(method = method, identifier = identifier, success = true, metadata = metadata)
    }

    fun failure(method: String, identifier: String?, reason: String? = null, metadata: Map<String, Any?>? = null) {
        AppLogger.authAttempt(method = method, identifier = identifier, success = false, reason = reason, metadata = metadata)
    }
}

fun Headers.toMap(): Map<String, String> {
    val map = LinkedHashMap<String, String>(size)
    for (i in 0 until size) {
        val name = name(i)
        val value = value(i)
        map[name] = value
    }
    return map
}